import httpx
import asyncio
import json
from typing import Dict, List, Optional, AsyncGenerator, Any

from rich.console import Console

console = Console()
from .config import ModelConfig
from .model_optimizer import ModelProfiler
from .quant_manager import DynamicQuantizationManager

class OllamaClient:
    """Client for interacting with Ollama API"""

    def _as_dict(self, obj, default=None):
        """Defensive helper to ensure object behaves like a dict"""
        if hasattr(obj, 'get') and callable(getattr(obj, 'get')):
            return obj
        return default or {}

    def __init__(self, model_config: ModelConfig):
        self.config = model_config
        self.base_url = model_config.base_url.rstrip('/')
        self.client = None
        self.profiler = ModelProfiler()
        self.quant_manager = DynamicQuantizationManager(self.base_url)
        self.interactive_mode = False  # Will be set to True by InteractiveMode
        self.history = None  # Will be set by InteractiveMode for debug access

    async def is_available(self) -> bool:
        """Check if Ollama service is available"""
        if not self.client:
            raise RuntimeError("OllamaClient must be used as async context manager")
        try:
            response = await self.client.get(f"{self.base_url}/api/tags")
            return response.status_code == 200
        except Exception as e:
            console.print(f"[red]Error checking Ollama availability: {e}[/red]")
            return False

    async def is_model_available(self) -> bool:
        """Check if the configured model is available"""
        if not self.client:
            raise RuntimeError("OllamaClient must be used as async context manager")
        try:
            response = await self.client.get(f"{self.base_url}/api/tags")
            if response.status_code == 200:
                models = response.json()
                models_dict = self._as_dict(models)
                model_names = [model['name'] for model in models_dict.get('models', [])]
                return self.config.name in model_names
            return False
        except:
            return False

    async def generate(
        self,
        prompt: str,
        system_prompt: Optional[str] = None,
        task_type: str = 'standard',
        num_predict_override: Optional[int] = None,
        temperature_override: Optional[float] = None,
        read_timeout_override: Optional[float] = None,
        options_override: Optional[Dict[str, Any]] = None,
        tools: Optional[List[Dict[str, Any]]] = None,
    ) -> str:
        """Generate text using the model"""
        if not self.client:
            raise RuntimeError("OllamaClient must be used as async context manager")

        messages = []

        # Track if we're attempting native tool calling
        attempting_native_tools = bool(tools)
        original_system_prompt = system_prompt  # Save for fallback

        # Always use system prompt - it contains tool definitions
        if system_prompt:
            messages.append({"role": "system", "content": system_prompt})
            if self.interactive_mode and hasattr(self, 'history') and hasattr(self.history, 'debug_timing') and self.history.debug_timing:
                console.print(f"[dim]DEBUG: System prompt sent to API ({len(system_prompt)} chars)[/dim]")
        else:
            console.print(f"[dim]Using model's built-in system prompt from modelfile[/dim]")

        messages.append({"role": "user", "content": prompt})

        # Apply model optimization
        base_config = {
            'temperature': self.config.temperature,
            'max_tokens': self.config.max_tokens
        }
        optimization_result = self.profiler.get_optimized_config(
            model_name=self.config.name,
            task_type=task_type,
            base_config=base_config
        )
        optimized_config = optimization_result.optimized_config

        # Get quantization recommendation (log-only during stabilization)
        try:
            quant_recommendation = self.quant_manager.recommend_quantization(
                model_base=self.config.name.split(':')[0],
                target_context=optimized_config.get('max_tokens', self.config.max_tokens),
                priority=optimized_config.get('priority', 'balanced')
            )
            recommended_model_name = quant_recommendation.get('recommended_model')
            if recommended_model_name and recommended_model_name != self.config.name:
                console.print(f"[dim]Quantization recommendation: {recommended_model_name} (not auto-switching)[/dim]")
        except Exception:
            pass

        # Apply simple overrides from caller (mode-based caps)
        if num_predict_override is not None:
            optimized_config['max_tokens'] = int(max(1, num_predict_override))
        if temperature_override is not None:
            optimized_config['temperature'] = float(temperature_override)

        payload = {
            "model": self.config.name,
            "messages": messages,
            "stream": False,
            "keep_alive": "5m",  # Keep model loaded for 5 minutes (much faster subsequent requests!)
            "options": {
                "temperature": optimized_config.get('temperature', self.config.temperature),
                "num_predict": optimized_config.get('max_tokens', self.config.max_tokens),
                **optimized_config.get('ollama_options', {}),
                "num_gpu": 999  # Force max GPU layers (-1 or 999 = use all available)
            }
        }

        # Add native tool support if tools provided
        # DISABLED: Native tool calling causes Ollama to hang in streaming mode
        # Using prompt-based tool calling for all models instead
        skip_native_tools = True  # Force prompt-based for all models

        if tools and not skip_native_tools:
            payload["tools"] = tools
            if self.interactive_mode and hasattr(self, 'history') and hasattr(self.history, 'debug_timing') and self.history.debug_timing:
                console.print(f"[dim]DEBUG: Native tool calling enabled ({len(tools)} tools)[/dim]")
        elif tools and skip_native_tools:
            console.print(f"[dim yellow]Model {self.config.name} doesn't support native tools - using prompt-based from start[/dim yellow]")
            # System prompt already added above with tool definitions - no need to insert again
            pass

        if options_override:
            try:
                payload["options"].update(options_override)
            except Exception:
                pass

        try:
            # Disable all timeouts - model loading can take 2+ minutes
            timeout = httpx.Timeout(None)

            # Single retry on transient request errors or option incompatibility
            last_exc = None
            payload_local = dict(payload)

            # Debug timing for API call
            if self.interactive_mode and hasattr(self, 'history') and hasattr(self.history, 'debug_timing') and self.history.debug_timing:
                import time
                api_start = time.time()
                console.print("[cyan]⏱ DEBUG: Sending request to Ollama API...[/cyan]")

            for attempt in range(2):
                try:
                    response = await self.client.post(
                        f"{self.base_url}/api/chat",
                        json=payload_local,
                        timeout=timeout
                    )
                    break
                except httpx.RequestError as e:
                    last_exc = e
                    if attempt == 0:
                        # brief backoff then retry once
                        await asyncio.sleep(0.5)
                        continue
                    raise
            # If server rejects request, handle specific errors
            if response.status_code >= 400:
                try:
                    error_text = response.text
                    # Check if error is due to unsupported tools
                    if 'does not support tools' in error_text and 'tools' in payload_local:
                        console.print(f"[yellow]Model doesn't support native tool calling, falling back to prompt-based[/yellow]")
                        payload_local = dict(payload_local)
                        payload_local.pop('tools', None)  # Remove tools
                        # Retry without tools
                        response = await self.client.post(
                            f"{self.base_url}/api/chat",
                            json=payload_local,
                            timeout=timeout
                        )
                    # remove any unknown options and retry once
                    elif attempt == 0 and 'options' in payload_local:
                        cleaned = dict(payload_local)
                        cleaned['options'] = {
                            k: v for k, v in payload_local['options'].items()
                            if k in {'temperature', 'num_predict'}
                        }
                        response = await self.client.post(
                            f"{self.base_url}/api/chat",
                            json=cleaned,
                            timeout=timeout
                        )
                except Exception:
                    pass
            
            if response.status_code == 200:
                if self.interactive_mode and hasattr(self, 'history') and hasattr(self.history, 'debug_timing') and self.history.debug_timing:
                    api_elapsed = time.time() - api_start
                    console.print(f"[cyan]⏱ DEBUG: Ollama API call took {api_elapsed:.3f}s (request to response)[/cyan]")

                result = response.json()
                message = self._as_dict(result.get('message', {}))
                content = message.get('content', '')

                # DEBUG: Log what model generated
                if self.interactive_mode and hasattr(self, 'history') and hasattr(self.history, 'debug_timing') and self.history.debug_timing:
                    console.print(f"[magenta]DEBUG: Model response length: {len(content)} chars[/magenta]")
                    if len(content) < 500:
                        console.print(f"[magenta]DEBUG: Full response: {content}[/magenta]")
                    else:
                        console.print(f"[magenta]DEBUG: First 300 chars: {content[:300]}[/magenta]")

                # Ensure we always return a string
                if not isinstance(content, str):
                    content = str(content) if content is not None else ''

                # If empty response, provide fallback
                if not content.strip():
                    content = f"Generated response for: {prompt[:50]}..." if len(prompt) > 50 else f"Generated response for: {prompt}"

                return content
            else:
                raise Exception(f"Ollama API error: {response.status_code} - {response.text}")
                
        except httpx.RequestError as e:
            # Provide more detailed error information
            error_context = f"Failed to connect to Ollama at {self.base_url}"
            if "timeout" in str(e).lower():
                error_context += f" (timeout - service unresponsive; you can cancel and retry)"
            elif "connection" in str(e).lower():
                error_context += f" (connection failed - ensure Ollama is running)"
            raise Exception(f"Request error: {error_context}. Details: {e}")
        except json.JSONDecodeError as e:
            raise Exception(f"JSON decode error: {e}")

    async def stream_generate(
        self,
        prompt: str,
        system_prompt: Optional[str] = None,
        task_type: str = 'standard',
        num_predict_override: Optional[int] = None,
        temperature_override: Optional[float] = None,
        options_override: Optional[Dict[str, Any]] = None,
        tools: Optional[List[Dict[str, Any]]] = None,
    ) -> AsyncGenerator[str, None]:
        """Generate text using the model with streaming"""
        if not self.client:
            raise RuntimeError("OllamaClient must be used as async context manager")

        messages = []

        # Track if we're attempting native tool calling
        attempting_native_tools = bool(tools)
        original_system_prompt = system_prompt  # Save for fallback

        # Always include system prompt - it contains critical tool definitions
        if system_prompt:
            messages.append({"role": "system", "content": system_prompt})

        messages.append({"role": "user", "content": prompt})

        # Apply model optimization
        # Apply model optimization using correct method name
        base_config = {
            'temperature': self.config.temperature,
            'max_tokens': self.config.max_tokens
        }
        optimization_result = self.profiler.get_optimized_config(
            model_name=self.config.name,
            task_type=task_type,
            base_config=base_config
        )
        optimized_config = optimization_result.optimized_config

        # Quantization recommendation disabled in streaming path to avoid overhead

        payload = {
            "model": self.config.name,
            "messages": messages,
            "stream": True,
            "keep_alive": "5m",  # Keep model loaded for 5 minutes
            "options": {
                "temperature": optimized_config.get('temperature', self.config.temperature),
                "num_predict": optimized_config.get('max_tokens', self.config.max_tokens),
                **optimized_config.get('ollama_options', {}),
                "num_gpu": 999  # Force max GPU layers (-1 or 999 = use all available)
            }

        }

        # Add native tool support if tools provided
        # DISABLED: Native tool calling causes Ollama to hang in streaming mode
        # Using prompt-based tool calling for all models instead
        skip_native_tools = True  # Force prompt-based for all models

        if tools and not skip_native_tools:
            payload["tools"] = tools
            if self.interactive_mode and hasattr(self, 'history') and hasattr(self.history, 'debug_timing') and self.history.debug_timing:
                console.print(f"[dim]DEBUG: Stream - Native tool calling enabled ({len(tools)} tools)[/dim]")
                console.print(f"[yellow]DEBUG: First tool schema: {json.dumps(tools[0], indent=2)[:300]}[/yellow]")
        elif tools and skip_native_tools:
            console.print(f"[dim yellow]Model {self.config.name} doesn't support native tools - using prompt-based from start[/dim yellow]")
            # System prompt already added above with tool definitions - no need to replace it
            pass

        # Apply overrides
        if num_predict_override is not None:
            payload['options']['num_predict'] = int(max(1, num_predict_override))
        if temperature_override is not None:
            payload['options']['temperature'] = float(temperature_override)
        if options_override:
            try:
                payload['options'].update(options_override)
            except Exception:
                pass

        try:
            if self.interactive_mode and hasattr(self, 'history') and hasattr(self.history, 'debug_timing') and self.history.debug_timing:
                console.print(f"[magenta]DEBUG: Full payload: {json.dumps(payload, indent=2)[:500]}...[/magenta]")
                console.print(f"[magenta]DEBUG: Sending stream request, tools_in_payload={'tools' in payload}[/magenta]")

            import time
            start_wait = time.time()
            console.print(f"[dim yellow]⏳ Sending request to Ollama API...[/dim yellow]")

            async with self.client.stream(
                "POST",
                f"{self.base_url}/api/chat",
                json=payload
            ) as response:
                wait_time = time.time() - start_wait
                console.print(f"[dim green]✓ Ollama responded in {wait_time:.2f}s (status: {response.status_code})[/dim green]")

                if self.interactive_mode and hasattr(self, 'history') and hasattr(self.history, 'debug_timing') and self.history.debug_timing:
                    console.print(f"[magenta]DEBUG: Got response status={response.status_code}[/magenta]")
                if response.status_code >= 400:
                    # Check if error is due to unsupported tools
                    error_text = await response.aread()
                    error_text = error_text.decode('utf-8')
                    if 'does not support tools' in error_text and 'tools' in payload:
                        console.print(f"[yellow]Model doesn't support native tool calling in streaming mode, retrying without tools[/yellow]")
                        payload_retry = dict(payload)
                        payload_retry.pop('tools', None)
                        # Re-add system prompt for prompt-based tool calling
                        if original_system_prompt:
                            payload_retry['messages'] = [{"role": "system", "content": original_system_prompt}, {"role": "user", "content": prompt}]
                            console.print(f"[dim cyan]Re-added system prompt ({len(original_system_prompt)} chars) for prompt-based tools[/dim cyan]")
                        # Retry without tools
                        async with self.client.stream("POST", f"{self.base_url}/api/chat", json=payload_retry) as response2:
                            if response2.status_code == 200:
                                async for line in response2.aiter_lines():
                                    if line.strip():
                                        try:
                                            data = json.loads(line)
                                            if 'message' in data and isinstance(data.get('message'), dict) and 'content' in data['message']:
                                                yield data['message']['content']
                                            if data.get('done', False):
                                                break
                                        except json.JSONDecodeError:
                                            continue
                            else:
                                raise Exception(f"Ollama API error: {response2.status_code}")
                            return
                    raise Exception(f"Ollama API error: {response.status_code}")

                if response.status_code == 200:
                    if self.interactive_mode and hasattr(self, 'history') and hasattr(self.history, 'debug_timing') and self.history.debug_timing:
                        console.print(f"[magenta]DEBUG: Status 200, starting to read lines...[/magenta]")

                    line_count = 0
                    async for line in response.aiter_lines():
                        line_count += 1
                        if line_count == 1:
                            console.print(f"[green]✓ First response chunk received from model[/green]")
                        if line.strip():
                            try:
                                data = json.loads(line)
                                if 'message' in data and isinstance(data.get('message'), dict) and 'content' in data['message']:
                                    yield data['message']['content']
                                if data.get('done', False):
                                    break
                            except json.JSONDecodeError:
                                continue
                    
        except httpx.RequestError as e:
            # Provide more detailed error information
            error_context = f"Failed to connect to Ollama at {self.base_url}"
            if "timeout" in str(e).lower():
                error_context += f" (timeout - try increasing timeout or reducing resource usage)"
            elif "connection" in str(e).lower():
                error_context += f" (connection failed - ensure Ollama is running)"
            raise Exception(f"Request error: {error_context}. Details: {e}")

    async def pull_model(self, model_name: str) -> bool:
        """Pull a model from Ollama"""
        if not self.client:
            raise RuntimeError("OllamaClient must be used as async context manager")

        payload = {"name": model_name}

        try:
            response = await self.client.post(
                f"{self.base_url}/api/pull",
                json=payload
            )
            return response.status_code == 200
        except:
            return False

    async def list_models(self) -> List[str]:
        """List all available models from Ollama"""
        if not self.client:
            raise RuntimeError("OllamaClient must be used as async context manager")
        try:
            response = await self.client.get(f"{self.base_url}/api/tags")
            if response.status_code == 200:
                models = response.json()
                models_dict = self._as_dict(models)
                return [model['name'] for model in models_dict.get('models', [])]
            return []
        except Exception as e:
            console.print(f"[red]Error listing models: {e}[/red]")
            return []

    async def unload_model(self, model_name: str = None) -> bool:
        """Unload a model from memory (stop keeping it loaded)

        Args:
            model_name: Model to unload. If None, unloads the current configured model.

        Returns:
            True if successful, False otherwise
        """
        if not self.client:
            raise RuntimeError("OllamaClient must be used as async context manager")

        target_model = model_name or self.config.name

        try:
            # Send empty generate request with keep_alive=0 to unload
            payload = {
                "model": target_model,
                "keep_alive": 0
            }
            response = await self.client.post(
                f"{self.base_url}/api/generate",
                json=payload,
                timeout=httpx.Timeout(connect=5.0, read=10.0, write=5.0, pool=None)
            )
            return response.status_code == 200
        except Exception as e:
            console.print(f"[dim]Note: Could not unload model {target_model}: {e}[/dim]")
            return False

    async def __aenter__(self):
        # Disable all timeouts - model loading can take 2+ minutes with limited GPU
        timeout = httpx.Timeout(None)
        self.client = httpx.AsyncClient(timeout=timeout)
        return self

    def update_config(self, model_config: ModelConfig):
        """Update the model configuration"""
        self.config = model_config
        self.base_url = model_config.base_url.rstrip('/')

    async def __aexit__(self, exc_type, exc_val, exc_tb):
        # Unload model before closing
        try:
            await self.unload_model()
        except Exception:
            pass

        if self.client:
            await self.client.aclose()
            self.client = None
